typedef enum {
  CLOSED, LISTEN, SYN_SENT, SYN_RCVD, ESTABLISHED
} TcpState;

typedef struct {
  TcpState state;
  int nextSeq;
  int expectedAck;
} Endpoint;

void threeWayHandshake(Endpoint *client, Endpoint *server) {
  int clientIsn = 1000;
  int serverIsn = 5000;

  client->state = CLOSED;
  server->state = LISTEN;
  client->state = SYN_SENT;
  sendSegment(client, server, SYN, clientIsn, 0);

  int receivedSyn = receiveSegment(server);
  server->expectedAck = receivedSyn + 1;
  server->nextSeq = serverIsn + 1;
  server->state = SYN_RCVD;
  sendSegment(server, client, SYN | ACK, serverIsn, server->expectedAck);

  int receivedSynAck = receiveSegment(client);
  client->expectedAck = serverIsn + 1;
  client->nextSeq = clientIsn + 1;
  client->state = ESTABLISHED;
  sendSegment(client, server, ACK, client->nextSeq, client->expectedAck);

  int receivedAck = receiveSegment(server);
  if (receivedAck == serverIsn + 1) {
    server->state = ESTABLISHED;
  }
}
